package ru.memearena.vote.infrastructure; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import ru.memearena.vote.domain.Vote; import java.time.Instant; import java.util.*; public interface VoteRepository extends JpaRepository<Vote,UUID>, JpaSpecificationExecutor<Vote>{ boolean existsByUserIdAndPairKey(UUID userId,String pairKey); @Query("select v from Vote v where v.createdAt >= :from") List<Vote> findSince(@Param("from") Instant from); }
